INSERT INTO restaurants (id, name, cuisine, description, image_url, rating, delivery_fee, delivery_min, delivery_max, address) OVERRIDING SYSTEM VALUE VALUES (1, 'Bella Napoli', 'Italian', 'Authentic Neapolitan cuisine crafted with imported Italian ingredients. Our wood-fired pizzas and handmade pastas bring the flavors of Naples to your doorstep.', 'https://images.unsplash.com/photo-1555396273-367ea4eb4db5?w=800&q=80', 4.8, 2.99, 25, 40, '701 Columbus Ave, San Francisco, CA 94133');
INSERT INTO restaurants (id, name, cuisine, description, image_url, rating, delivery_fee, delivery_min, delivery_max, address) OVERRIDING SYSTEM VALUE VALUES (2, 'Sakura Garden', 'Japanese', 'Exquisite Japanese cuisine featuring the freshest fish for sushi, traditional ramen, and seasonal specialties prepared by our master chef trained in Tokyo.', 'https://images.unsplash.com/photo-1579871494447-9811cf80d66c?w=800&q=80', 4.7, 3.99, 30, 50, '1737 Post St, San Francisco, CA 94115');
INSERT INTO restaurants (id, name, cuisine, description, image_url, rating, delivery_fee, delivery_min, delivery_max, address) OVERRIDING SYSTEM VALUE VALUES (3, 'Casa Fuego', 'Mexican', 'Vibrant Mexican street food and traditional dishes made with authentic recipes passed down through generations. Fresh ingredients, bold flavors, and fiery salsas.', 'https://images.unsplash.com/photo-1565299585323-38d6b0865b47?w=800&q=80', 4.6, 1.99, 20, 35, '2889 Mission St, San Francisco, CA 94110');
INSERT INTO restaurants (id, name, cuisine, description, image_url, rating, delivery_fee, delivery_min, delivery_max, address) OVERRIDING SYSTEM VALUE VALUES (4, 'Spice Route', 'Indian', 'A culinary journey through India''s diverse regional cuisines. From the creamy kormas of the North to the fiery vindaloos of Goa, every dish is crafted with freshly ground spices.', 'https://images.unsplash.com/photo-1585937421612-70a008356fbe?w=800&q=80', 4.7, 2.49, 30, 50, '533 O''Farrell St, San Francisco, CA 94102');
INSERT INTO restaurants (id, name, cuisine, description, image_url, rating, delivery_fee, delivery_min, delivery_max, address) OVERRIDING SYSTEM VALUE VALUES (5, 'Golden Dragon', 'Chinese', 'Traditional Chinese cuisine spanning Cantonese dim sum, Sichuan specialties, and Cantonese seafood dishes. Family recipes perfected over three generations.', 'https://images.unsplash.com/photo-1563245372-f21724e3856d?w=800&q=80', 4.5, 1.99, 25, 40, '744 Washington St, San Francisco, CA 94108');
INSERT INTO restaurants (id, name, cuisine, description, image_url, rating, delivery_fee, delivery_min, delivery_max, address) OVERRIDING SYSTEM VALUE VALUES (6, 'Le Petit Bistro', 'French', 'A charming Parisian bistro bringing classic French cuisine to your table. From delicate starters to rich cassoulet, our chef sources only the finest ingredients.', 'https://images.unsplash.com/photo-1414235077428-338989a2e8c0?w=800&q=80', 4.9, 4.99, 35, 55, '345 Powell St, San Francisco, CA 94102');
INSERT INTO restaurants (id, name, cuisine, description, image_url, rating, delivery_fee, delivery_min, delivery_max, address) OVERRIDING SYSTEM VALUE VALUES (7, 'Olive & Sea', 'Mediterranean', 'Sun-drenched Mediterranean flavors from Greece, Lebanon, and Turkey. Fresh seafood, vibrant mezze, and wood-fired grills inspired by the azure Mediterranean coast.', 'https://images.unsplash.com/photo-1544025162-d76694265947?w=800&q=80', 4.6, 2.99, 25, 45, '2246 Chestnut St, San Francisco, CA 94123');
INSERT INTO restaurants (id, name, cuisine, description, image_url, rating, delivery_fee, delivery_min, delivery_max, address) OVERRIDING SYSTEM VALUE VALUES (8, 'Seoul Kitchen', 'Korean', 'Authentic Korean cuisine from classic BBQ to modern Korean-fusion dishes. We serve the soul of Seoul — from comforting stews to the thrill of tabletop grilling.', 'https://images.unsplash.com/photo-1498654896293-37aacf113fd9?w=800&q=80', 4.7, 2.99, 25, 45, '308 5th Ave, San Francisco, CA 94118');
INSERT INTO restaurants (id, name, cuisine, description, image_url, rating, delivery_fee, delivery_min, delivery_max, address) OVERRIDING SYSTEM VALUE VALUES (9, 'Thai Orchid', 'Thai', 'Authentic Thai cuisine bursting with fragrant herbs and bold flavors. Our dishes balance the five pillars of Thai cooking: sweet, sour, salty, spicy, and umami.', 'https://images.unsplash.com/photo-1562802378-063ec186a863?w=800&q=80', 4.6, 2.49, 25, 40, '1234 Irving St, San Francisco, CA 94122');
INSERT INTO restaurants (id, name, cuisine, description, image_url, rating, delivery_fee, delivery_min, delivery_max, address) OVERRIDING SYSTEM VALUE VALUES (10, 'The American Grill', 'American', 'Classic American comfort food done right. Premium burgers, smoked BBQ ribs, and all-day breakfast favorites. Big portions, bold flavors, and everything made from scratch.', 'https://images.unsplash.com/photo-1555396273-367ea4eb4db5?w=800&q=80', 4.4, 0.99, 20, 35, '555 Mission St, San Francisco, CA 94105');
INSERT INTO restaurants (id, name, cuisine, description, image_url, rating, delivery_fee, delivery_min, delivery_max, address) OVERRIDING SYSTEM VALUE VALUES (11, 'Trattoria Roma', 'Italian', 'A rustic Roman trattoria serving classic recipes passed down through generations. From creamy cacio e pepe to slow-braised oxtail, every dish is a love letter to the Eternal City.', 'https://images.unsplash.com/photo-1414235077428-338989a2e8c0?w=800&q=80', 4.6, 3.49, 30, 50, '4072 18th St, San Francisco, CA 94114');
INSERT INTO restaurants (id, name, cuisine, description, image_url, rating, delivery_fee, delivery_min, delivery_max, address) OVERRIDING SYSTEM VALUE VALUES (12, 'Ramen Kazu', 'Japanese', 'Tokyo-trained chef Kazu brings authentic Japanese ramen to San Francisco. Rich tonkotsu broths, perfectly springy noodles, and creative toppings crafted with obsessive attention to detail.', 'https://images.unsplash.com/photo-1569718212165-3a8278d5f624?w=800&q=80', 4.7, 2.49, 20, 35, '175 2nd St, San Francisco, CA 94105');
INSERT INTO restaurants (id, name, cuisine, description, image_url, rating, delivery_fee, delivery_min, delivery_max, address) OVERRIDING SYSTEM VALUE VALUES (13, 'El Taquero', 'Mexican', 'Street-style tacos and bold Mexican flavors inspired by the taquerias of Mexico City. Everything is made fresh daily — from hand-pressed tortillas to slow-cooked meats simmered with dried chiles and spices.', 'https://images.unsplash.com/photo-1565299585323-38d6b0865b47?w=800&q=80', 4.5, 1.99, 15, 30, '2400 Mission St, San Francisco, CA 94110');
INSERT INTO restaurants (id, name, cuisine, description, image_url, rating, delivery_fee, delivery_min, delivery_max, address) OVERRIDING SYSTEM VALUE VALUES (14, 'Masala House', 'Indian', 'Contemporary Indian cuisine celebrating the diverse regional cooking of the subcontinent. From smoky Punjabi tandoor dishes to fragrant Kerala seafood curries, each plate tells a delicious story.', 'https://images.unsplash.com/photo-1585937421612-70a008356fbe?w=800&q=80', 4.6, 2.99, 25, 45, '1700 Haight St, San Francisco, CA 94117');
INSERT INTO restaurants (id, name, cuisine, description, image_url, rating, delivery_fee, delivery_min, delivery_max, address) OVERRIDING SYSTEM VALUE VALUES (15, 'Dragon Palace', 'Chinese', 'Authentic Cantonese banquet cooking brought to your table. Our chefs trained in Hong Kong specialty restaurants, bringing traditional dim sum, whole fish, and wok-tossed classics to the Sunset District.', 'https://images.unsplash.com/photo-1563245372-f21724e3856d?w=800&q=80', 4.4, 3.99, 30, 50, '2801 Judah St, San Francisco, CA 94122');
INSERT INTO restaurants (id, name, cuisine, description, image_url, rating, delivery_fee, delivery_min, delivery_max, address) OVERRIDING SYSTEM VALUE VALUES (16, 'Bistro Léon', 'French', 'A convivial Lyonnaise bouchon in the heart of Noe Valley. Chef Léon serves hearty Lyonnais classics — quenelles, gratins, and the finest steak frites — alongside a thoughtfully curated wine list.', 'https://images.unsplash.com/photo-1414235077428-338989a2e8c0?w=800&q=80', 4.5, 3.99, 35, 55, '4016 24th St, San Francisco, CA 94114');
INSERT INTO restaurants (id, name, cuisine, description, image_url, rating, delivery_fee, delivery_min, delivery_max, address) OVERRIDING SYSTEM VALUE VALUES (17, 'Aegean Table', 'Mediterranean', 'A modern mezze bar celebrating the coastal cuisines of Greece, Turkey, and Lebanon. Share small plates, sip natural wines, and let the flavors of the Aegean transport you to a sun-drenched terrace by the sea.', 'https://images.unsplash.com/photo-1544025162-d76694265947?w=800&q=80', 4.7, 2.99, 25, 40, '500 Hayes St, San Francisco, CA 94102');
INSERT INTO restaurants (id, name, cuisine, description, image_url, rating, delivery_fee, delivery_min, delivery_max, address) OVERRIDING SYSTEM VALUE VALUES (18, 'Hangang BBQ', 'Korean', 'Premium Korean barbecue with high-grade meats, house-made marinades, and a full array of banchan. Our charcoal grills and expert table service deliver the ultimate Korean dining experience at home.', 'https://images.unsplash.com/photo-1590301157890-4810ed352733?w=800&q=80', 4.8, 3.49, 30, 50, '4001 Geary Blvd, San Francisco, CA 94118');
INSERT INTO restaurants (id, name, cuisine, description, image_url, rating, delivery_fee, delivery_min, delivery_max, address) OVERRIDING SYSTEM VALUE VALUES (19, 'Siam Street', 'Thai', 'Regional Thai cooking that goes far beyond the usual. From the coconut-rich curries of the South to the herbaceous, fiery dishes of Isaan, Siam Street takes you on a journey through Thailand''s incredible culinary geography.', 'https://images.unsplash.com/photo-1562565652-a0d8f0c59eb4?w=800&q=80', 4.6, 2.49, 20, 35, '4652 Mission St, San Francisco, CA 94112');
INSERT INTO restaurants (id, name, cuisine, description, image_url, rating, delivery_fee, delivery_min, delivery_max, address) OVERRIDING SYSTEM VALUE VALUES (20, 'Pit Stop BBQ', 'American', 'Low and slow is the only way we know. Our pitmasters smoke meats over California oak for 12–18 hours, producing ribs, brisket, and pulled pork with bark so good you''ll want to eat it by itself.', 'https://images.unsplash.com/photo-1544025162-d76694265947?w=800&q=80', 4.7, 2.99, 25, 45, '1200 Tennessee St, San Francisco, CA 94107');
