INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (1, NULL, 1, NULL, 5, 'The Margherita pizza is pure perfection — thin charred crust with the freshest mozzarella. Transported me straight to Naples.', 'Sarah M.', NOW() - INTERVAL '2 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (2, NULL, 1, NULL, 5, 'Carbonara arrived at exactly the right temperature with a silky sauce. You can taste the quality of the guanciale. Exceptional.', 'James T.', NOW() - INTERVAL '5 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (3, NULL, 1, NULL, 5, 'Tiramisu is the best I''ve had outside of Italy. Perfectly soaked ladyfingers, not too sweet. Absolutely divine.', 'Michael R.', NOW() - INTERVAL '10 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (4, NULL, 1, NULL, 4, 'Burrata was unbelievably creamy and the prosciutto was paper-thin perfection. Really excellent, delivery was fast too.', 'Emma L.', NOW() - INTERVAL '14 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (5, NULL, 1, NULL, 4, 'The Diavola had a beautiful kick and the wood-fired crust was genuinely special. Will order again for sure.', 'Lisa C.', NOW() - INTERVAL '19 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (6, NULL, 1, NULL, 3, 'Pizza was good but arrived a bit lukewarm. The flavors were there though. Would try pickup next time.', 'Tom H.', NOW() - INTERVAL '25 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (7, NULL, 1, NULL, 3, 'Solid Italian food — nothing revolutionary but reliably good. The carbonara was a touch too salty for my taste.', 'Priya S.', NOW() - INTERVAL '31 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (8, NULL, 1, NULL, 2, 'Waited over an hour for delivery and the pasta was overcooked and clumped together by then. Disappointing for the price.', 'Ryan P.', NOW() - INTERVAL '38 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (9, NULL, 1, NULL, 1, 'Order completely wrong — got someone else''s pizza with meat even though I''m vegetarian. Customer service didn''t help resolve it.', 'Sophie W.', NOW() - INTERVAL '45 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (10, NULL, 1, NULL, 4, 'Pappardelle ragù was rich and hearty. Huge portions too. My go-to Italian spot now.', 'Anthony B.', NOW() - INTERVAL '52 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (11, NULL, 2, NULL, 5, 'The dragon roll was absolutely stunning — perfectly balanced flavors and arrived in beautiful presentation. Best sushi delivery I''ve tried.', 'David K.', NOW() - INTERVAL '3 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (12, NULL, 2, NULL, 5, 'Tonkotsu ramen broth was rich, milky, and clearly made from scratch. The chashu pork melted in my mouth. Incredible.', 'Amy N.', NOW() - INTERVAL '8 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (13, NULL, 2, NULL, 5, 'Matcha cheesecake was an absolute revelation — creamy, aromatic, and not overly sweet. Will order just for that.', 'Sophie W.', NOW() - INTERVAL '14 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (14, NULL, 2, NULL, 4, 'Really fresh sashimi. The salmon was incredibly silky. Docking a star only because the miso soup arrived slightly cold.', 'Ryan P.', NOW() - INTERVAL '20 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (15, NULL, 2, NULL, 4, 'Gyoza were perfectly crispy with juicy filling. The yuzu ponzu dipping sauce was a lovely touch. Really good.', 'Tom H.', NOW() - INTERVAL '27 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (16, NULL, 2, NULL, 3, 'Decent sushi but nothing mind-blowing for the price. Fish was fresh though and delivery was prompt.', 'Nadia C.', NOW() - INTERVAL '34 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (17, NULL, 2, NULL, 3, 'Average ramen — broth was a bit thin compared to what you''d get in a proper ramen shop. Fine for delivery.', 'Frank D.', NOW() - INTERVAL '41 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (18, NULL, 2, NULL, 2, 'Rice in my nigiri was too warm and falling apart. Didn''t feel great eating warm sushi. Flavors were okay though.', 'Claire F.', NOW() - INTERVAL '50 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (19, NULL, 3, NULL, 5, 'Al pastor tacos are simply the best in the city. The pineapple-marinated pork is incredible and the tortillas are hand-pressed. Perfection.', 'Carlos M.', NOW() - INTERVAL '2 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (20, NULL, 3, NULL, 5, 'Birria tacos with the consommé for dipping arrived perfectly packaged. The cheese pull was real. Outstanding.', 'Jessica R.', NOW() - INTERVAL '6 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (21, NULL, 3, NULL, 5, 'Churros arrived crispy and warm — the Mexican chocolate sauce was deeply complex. Best churros outside Mexico City.', 'Derek L.', NOW() - INTERVAL '11 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (22, NULL, 3, NULL, 5, 'Veggie burrito was loaded with fresh roasted vegetables and the salsa verde had real heat. Great vegetarian option.', 'Natalie G.', NOW() - INTERVAL '16 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (23, NULL, 3, NULL, 4, 'Great burrito — generously filled with quality carne asada, fresh guacamole, and proper black beans. Solid.', 'Marco V.', NOW() - INTERVAL '22 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (24, NULL, 3, NULL, 4, 'Guacamole was made fresh and perfectly seasoned with lime. Chips stayed crispy somehow. Impressive packaging.', 'Brianna T.', NOW() - INTERVAL '28 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (25, NULL, 3, NULL, 3, 'Tacos were tasty but smaller than expected for the price. Salsa verde had good flavor though. Average overall.', 'Omar A.', NOW() - INTERVAL '34 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (26, NULL, 3, NULL, 3, 'Decent Mexican food. The carnitas were a bit dry but the toppings helped. Not bad but not amazing.', 'Hannah B.', NOW() - INTERVAL '42 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (27, NULL, 3, NULL, 2, 'My order arrived missing an item and the rice was hard. Not great for the price point. Disappointing.', 'Vikram N.', NOW() - INTERVAL '50 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (28, NULL, 3, NULL, 1, 'Food was cold and tasted like it had been sitting for a while. Tortillas were stiff and flavorless. Won''t order again.', 'Linda C.', NOW() - INTERVAL '58 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (29, NULL, 3, NULL, 4, 'Tres leches cake was a wonderful end to the meal — soaked perfectly and topped with fresh cream. Loved it.', 'Grace Y.', NOW() - INTERVAL '65 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (30, NULL, 3, NULL, 4, 'Elote en vaso is addictive. Great depth of flavor from the cotija and chili. Really solid across the board.', 'Kevin W.', NOW() - INTERVAL '72 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (31, NULL, 4, NULL, 5, 'Butter chicken was absolutely divine — the sauce was silky, aromatic, and perfectly spiced. Best I''ve had outside Mumbai.', 'Anita P.', NOW() - INTERVAL '3 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (32, NULL, 4, NULL, 5, 'Lamb rogan josh was a masterpiece. The slow-cooked meat fell apart and the spice blend was complex and beautiful.', 'Raj K.', NOW() - INTERVAL '9 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (33, NULL, 4, NULL, 4, 'Really good biryani with fragrant saffron rice and well-seasoned chicken. The garlic naan was pillowy perfection.', 'Claire F.', NOW() - INTERVAL '16 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (34, NULL, 4, NULL, 4, 'Paneer tikka was beautifully charred and the marinade had real depth. Great appetizer. Will definitely reorder.', 'Omar A.', NOW() - INTERVAL '23 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (35, NULL, 4, NULL, 3, 'Tikka masala was fine — a bit safe and mild compared to what I was hoping for. The naan was excellent though.', 'Hannah B.', NOW() - INTERVAL '30 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (36, NULL, 4, NULL, 2, 'Delivery was extremely late and the food arrived cold. The curry was good in flavor but it''s hard to enjoy cold Indian food.', 'Steven J.', NOW() - INTERVAL '40 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (37, NULL, 4, NULL, 1, 'Way too bland — no heat whatsoever. Asked for spicy and got something that tasted like tomato soup. Very disappointing.', 'Grace Y.', NOW() - INTERVAL '52 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (38, NULL, 5, NULL, 5, 'Dim sum is the real deal — har gow wrappers were translucent and delicate, the siu mai were plump. Outstanding quality.', 'Mei L.', NOW() - INTERVAL '4 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (39, NULL, 5, NULL, 5, 'Peking duck was incredible — that lacquered skin arrived crispy somehow. The pancakes and hoisin made it sing.', 'Linda C.', NOW() - INTERVAL '9 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (40, NULL, 5, NULL, 5, 'Beef chow fun had incredible wok hei — you could taste the fire. This is the real stuff, not the Americanized version.', 'Kevin W.', NOW() - INTERVAL '15 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (41, NULL, 5, NULL, 4, 'Kung pao chicken had a great balance of heat, sweetness, and crunch. Generous portions too. Solid Chinese food.', 'Frank D.', NOW() - INTERVAL '21 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (42, NULL, 5, NULL, 4, 'Hot and sour soup was bold, tangy, and deeply comforting. The wonton soup was clean and flavorful.', 'Grace Y.', NOW() - INTERVAL '28 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (43, NULL, 5, NULL, 3, 'Good dim sum but arrived a bit cool. Some items were better than others. The BBQ pork bao was excellent though.', 'Steven J.', NOW() - INTERVAL '35 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (44, NULL, 5, NULL, 3, 'Average fried rice — not bad, not memorable. The spring rolls were decent. Nothing special here.', 'Isabelle D.', NOW() - INTERVAL '43 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (45, NULL, 5, NULL, 2, 'Ordered mapo tofu and it arrived way too watery. The flavor was there but the texture was completely wrong.', 'Pierre M.', NOW() - INTERVAL '52 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (46, NULL, 5, NULL, 1, 'Order was wrong, waited an hour, and when it arrived the noodles were mushy. Very disappointing experience.', 'Charlotte B.', NOW() - INTERVAL '62 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (47, NULL, 6, NULL, 5, 'Steak frites was absolutely impeccable — the bavette was tender, the frites crispy, and the béarnaise was flawless. Bravo.', 'Isabelle D.', NOW() - INTERVAL '3 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (48, NULL, 6, NULL, 5, 'Bouillabaisse arrived in a thermal container still bubbling. The saffron broth was extraordinary. Felt like being in Marseille.', 'Pierre M.', NOW() - INTERVAL '8 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (49, NULL, 6, NULL, 5, 'Chocolate fondant had a perfectly molten center and the vanilla ice cream alongside was exceptional. A perfect finish.', 'William F.', NOW() - INTERVAL '14 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (50, NULL, 6, NULL, 4, 'Crème brûlée had a perfect caramel crust. The custard was silky and lightly scented with vanilla. Wonderful dessert.', 'Charlotte B.', NOW() - INTERVAL '20 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (51, NULL, 6, NULL, 3, 'French onion soup was good but the bread got soggy in delivery. Flavors were authentic though. Mixed experience.', 'Camille R.', NOW() - INTERVAL '28 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (52, NULL, 6, NULL, 2, 'Expensive for the portion sizes and the sole arrived overcooked and dry. Expected much more for the price.', 'Étienne L.', NOW() - INTERVAL '38 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (53, NULL, 7, NULL, 5, 'The mezze platter is the most generous and authentic I''ve found anywhere. Everything from the hummus to the falafel was exceptional.', 'Sophia K.', NOW() - INTERVAL '2 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (54, NULL, 7, NULL, 5, 'Lamb souvlaki was beautifully marinated and the tzatziki was made with real strained yogurt. Superb.', 'Yasmin A.', NOW() - INTERVAL '6 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (55, NULL, 7, NULL, 5, 'Falafel bowl with saffron rice was an incredibly satisfying vegetarian meal. Everything was fresh and vibrant.', 'Elena V.', NOW() - INTERVAL '11 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (56, NULL, 7, NULL, 4, 'Grilled branzino was perfectly cooked and the herb oil was fragrant and bright. One of my favorite deliveries ever.', 'Nicholas P.', NOW() - INTERVAL '17 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (57, NULL, 7, NULL, 4, 'Hummus is the real deal — smooth, well-seasoned, with a good olive oil drizzle. Warm pita was a nice touch.', 'George T.', NOW() - INTERVAL '23 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (58, NULL, 7, NULL, 4, 'Baklava was crispy, honeyed, and not overly sweet. The filo layers were delicate. Great dessert.', 'Hassan R.', NOW() - INTERVAL '30 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (59, NULL, 7, NULL, 4, 'Shrimp saganaki was rich and saucy with good feta. Really delicious for a cold evening. Will order again.', 'Omar A.', NOW() - INTERVAL '37 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (60, NULL, 7, NULL, 3, 'Calamari was a bit chewy which is disappointing. The accompanying sauce was nice though. Inconsistent quality.', 'Anita P.', NOW() - INTERVAL '44 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (61, NULL, 7, NULL, 3, 'Kibbeh were okay but a bit greasy. The hummus and pita were the highlights for me. Mixed experience.', 'Raj K.', NOW() - INTERVAL '52 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (62, NULL, 7, NULL, 2, 'Spanakopita phyllo was completely soggy from condensation — a packaging problem. Filing was tasty but texturally ruined.', 'Claire F.', NOW() - INTERVAL '61 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (63, NULL, 7, NULL, 1, 'Order arrived missing half the mezze items and the restaurant was unresponsive when I tried to contact them.', 'Vikram N.', NOW() - INTERVAL '72 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (64, NULL, 8, NULL, 5, 'Best bibimbap I''ve had outside of Seoul. The stone pot effect was replicated beautifully — crispy rice bottom and all.', 'Jisoo L.', NOW() - INTERVAL '4 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (65, NULL, 8, NULL, 5, 'Japchae noodles were beautifully seasoned and loaded with vegetables. The best Korean glass noodle dish I''ve had delivered.', 'Min J.', NOW() - INTERVAL '11 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (66, NULL, 8, NULL, 4, 'Tteokbokki arrived bubbling in a great gochujang sauce. Chewy rice cakes were perfectly cooked. Good stuff.', 'Chris O.', NOW() - INTERVAL '19 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (67, NULL, 8, NULL, 3, 'Decent Korean food but the banchan were minimal. Bulgogi was tasty though. Average delivery experience.', 'Rachel S.', NOW() - INTERVAL '28 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (68, NULL, 8, NULL, 2, 'The galbi was overpriced for the amount received. Tough and not particularly flavorful. Disappointing.', 'Daniel Y.', NOW() - INTERVAL '40 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (69, NULL, 9, NULL, 5, 'Pad Thai is an absolute masterpiece — perfectly balanced sweet, sour, and salty. The texture of the noodles was flawless.', 'Malee S.', NOW() - INTERVAL '2 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (70, NULL, 9, NULL, 5, 'Green curry was aromatic, creamy, and had beautiful depth. The bamboo shoots and Thai eggplant added great texture.', 'Jason W.', NOW() - INTERVAL '5 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (71, NULL, 9, NULL, 5, 'Tom yum goong was explosively flavorful — sour, spicy, and fragrant with real lemongrass and galangal. Outstanding.', 'Nadia C.', NOW() - INTERVAL '9 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (72, NULL, 9, NULL, 5, 'Miang kham was unlike anything I''ve had delivered before. Such a unique and delicious combination of flavors.', 'Robert T.', NOW() - INTERVAL '13 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (73, NULL, 9, NULL, 4, 'Massaman curry was rich and warming. The potatoes were creamy and the beef tender. A minor complaint: slightly oily.', 'Alicia H.', NOW() - INTERVAL '18 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (74, NULL, 9, NULL, 4, 'Satay chicken was well marinated and the peanut sauce was thick and deeply flavored. Great starter.', 'Ben M.', NOW() - INTERVAL '23 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (75, NULL, 9, NULL, 4, 'Som tum papaya salad was fresh and fiery. The balance of flavors was excellent. Really loved it.', 'Camille R.', NOW() - INTERVAL '29 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (76, NULL, 9, NULL, 4, 'Green curry was excellent and the jasmine rice was perfectly cooked. Good portion sizes too.', 'Étienne L.', NOW() - INTERVAL '35 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (77, NULL, 9, NULL, 3, 'Basil stir-fry was okay — a bit too sweet for my taste. Not bad, just not what I was hoping for.', 'Sophia K.', NOW() - INTERVAL '42 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (78, NULL, 9, NULL, 3, 'Mango sticky rice was good but the mango wasn''t quite ripe enough. The rice itself was good though.', 'Yasmin A.', NOW() - INTERVAL '49 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (79, NULL, 9, NULL, 3, 'Spring rolls were fine — crispy but a bit bland inside. The sweet chili sauce saved them. Average.', 'George T.', NOW() - INTERVAL '57 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (80, NULL, 9, NULL, 2, 'Tom kha was thin and coconut milk seemed watered down. Not the fragrant, rich soup I was expecting.', 'Hassan R.', NOW() - INTERVAL '66 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (81, NULL, 9, NULL, 2, 'Delivery took 75 minutes and everything was cold. The flavors were probably decent but hard to tell.', 'Nicholas P.', NOW() - INTERVAL '76 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (82, NULL, 9, NULL, 1, 'Wrong order delivered. Got something completely different. No response from the restaurant. Terrible experience.', 'Elena V.', NOW() - INTERVAL '88 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (83, NULL, 10, NULL, 5, 'The smash burger is one of the best burgers I''ve had — crispy lacey edges, juicy center, and that special sauce is incredible.', 'Tyler B.', NOW() - INTERVAL '3 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (84, NULL, 10, NULL, 5, 'BBQ ribs were fall-off-the-bone tender with a bark that would make Texas proud. Incredible from a delivery service.', 'Ashley M.', NOW() - INTERVAL '7 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (85, NULL, 10, NULL, 5, 'Chicken and waffles with that maple syrup and hot sauce combo was absolutely amazing. Sweet, savory, crispy perfection.', 'Megan T.', NOW() - INTERVAL '13 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (86, NULL, 10, NULL, 4, 'Buffalo wings were properly crispy and the sauce had a real kick. Blue cheese dip was housemade and excellent.', 'Brandon K.', NOW() - INTERVAL '19 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (87, NULL, 10, NULL, 4, 'The Philly cheesesteak was loaded with properly seasoned ribeye and the provolone was melted perfectly. Solid.', 'Kayla R.', NOW() - INTERVAL '26 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (88, NULL, 10, NULL, 3, 'Classic smash burger was good but nothing that blew me away. Fries arrived a bit soft. Decent comfort food.', 'Josh L.', NOW() - INTERVAL '33 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (89, NULL, 10, NULL, 3, 'Mac and cheese bites were fine — a bit heavy. The cheesecake was the highlight of the order actually.', 'Brianna T.', NOW() - INTERVAL '41 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (90, NULL, 10, NULL, 2, 'Ordered my steak medium-rare and it arrived well done. Completely different experience than expected. Disappointing.', 'Derek L.', NOW() - INTERVAL '51 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (91, NULL, 10, NULL, 1, 'Food was cold, burger was soggy, and the fries were limp. Paid premium prices for average fast food quality. Never again.', 'Natalie G.', NOW() - INTERVAL '63 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (92, NULL, 11, NULL, 5, 'Cacio e pepe was executed with real Roman precision — just the right pepper and the sauce was perfectly emulsified. Better than Rome.', 'Marco F.', NOW() - INTERVAL '3 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (93, NULL, 11, NULL, 5, 'Supplì were crispy outside, molten inside with ragù and mozzarella. Extraordinary — better than what I had in Trastevere.', 'Rachel S.', NOW() - INTERVAL '7 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (94, NULL, 11, NULL, 5, 'Bucatini all''Amatriciana was deeply flavorful with proper guanciale. Perfectly al dente. This is the real deal.', 'Giulia R.', NOW() - INTERVAL '12 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (95, NULL, 11, NULL, 4, 'Really excellent pasta. The bucatini was al dente and the guanciale was top quality. Only wish portions were a bit bigger.', 'Nina B.', NOW() - INTERVAL '18 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (96, NULL, 11, NULL, 4, 'Semifreddo al torroncino was an elegant and unusual dessert — the nougat flavor was distinctive and wonderful.', 'Patrick O.', NOW() - INTERVAL '25 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (97, NULL, 11, NULL, 3, 'Risotto ai funghi arrived a bit gluey from delivery. Flavors were good though. Would try pickup next time.', 'Sophia K.', NOW() - INTERVAL '33 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (98, NULL, 11, NULL, 2, 'The gnocchi alla Romana were dense and heavy. Expected more finesse for the price. Disappointed.', 'George T.', NOW() - INTERVAL '43 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (99, NULL, 11, NULL, 1, 'Order arrived an hour late, food was cold, and wrong pasta was sent. Refund process was a nightmare.', 'Elena V.', NOW() - INTERVAL '55 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (100, NULL, 12, NULL, 5, 'The tonkotsu broth is milky, rich, and has clearly been simmered for hours. Best ramen I''ve had delivered anywhere in the city.', 'Kevin T.', NOW() - INTERVAL '2 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (101, NULL, 12, NULL, 5, 'Spicy miso ramen hit every note — the depth of the miso, the heat of the chili oil, the perfectly soft egg. Absolutely incredible.', 'Yuki H.', NOW() - INTERVAL '5 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (102, NULL, 12, NULL, 5, 'Shoyu ramen had a beautifully clear broth with brilliant clarity of flavor. The yuzu notes made it sing. Exceptional.', 'Lauren M.', NOW() - INTERVAL '9 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (103, NULL, 12, NULL, 5, 'Salmon ikura don was spectacular — sashimi-grade salmon over perfectly seasoned rice with beautiful roe. A stunning bowl.', 'Priya K.', NOW() - INTERVAL '14 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (104, NULL, 12, NULL, 4, 'Karaage chicken was super crispy and juicy. The dipping sauce was excellent. Great starter before the ramen.', 'Sam W.', NOW() - INTERVAL '19 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (105, NULL, 12, NULL, 4, 'Chashu don was a beautiful bowl — glossy pork belly over perfectly seasoned rice with a jammy egg. Very satisfying.', 'Michelle L.', NOW() - INTERVAL '25 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (106, NULL, 12, NULL, 4, 'Gyoza had a lovely crispy skirt and the filling was juicy. Yuzu ponzu was a nice twist on the classic. Really good.', 'Henry K.', NOW() - INTERVAL '31 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (107, NULL, 12, NULL, 3, 'Ramen was good but noodles had softened a bit in delivery. Still enjoyable though. Would try pickup for the full experience.', 'Sophie Z.', NOW() - INTERVAL '38 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (108, NULL, 12, NULL, 3, 'Average tonkotsu — nothing wrong with it but didn''t blow me away. Decent for delivery on a Tuesday night.', 'Jason W.', NOW() - INTERVAL '46 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (109, NULL, 12, NULL, 2, 'Vegan shio ramen was very thin and lacking depth. Expected more complexity from a specialist ramen restaurant. Bland.', 'Emma T.', NOW() - INTERVAL '56 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (110, NULL, 12, NULL, 1, 'Received completely wrong order. When I called, was put on hold for 20 minutes. Eventually gave up. Very disappointing.', 'Robert N.', NOW() - INTERVAL '68 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (111, NULL, 13, NULL, 5, 'Birria tacos were a revelation — the consommé arrived separately and the cheese-dipped tortilla had a perfect crisp. Incredible.', 'Carlos V.', NOW() - INTERVAL '4 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (112, NULL, 13, NULL, 5, 'Taco de lengua was the most tender, flavorful beef tongue I''ve ever had. The salsa verde was vibrant and bright. Stunning.', 'Isabel C.', NOW() - INTERVAL '9 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (113, NULL, 13, NULL, 5, 'Tostadas de tinga were incredible — crispy base, shredded chicken with brilliant chipotle flavor, and cool crema. Loved it.', 'Maria G.', NOW() - INTERVAL '15 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (114, NULL, 13, NULL, 4, 'Enchiladas verdes were properly sauced and the chicken filling was moist. Great tomatillo sauce. Really good.', 'Roberto M.', NOW() - INTERVAL '22 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (115, NULL, 13, NULL, 4, 'Queso fundido arrived still bubbling with Oaxacan cheese. The fresh tortillas were soft and delicious. Great starter.', 'Jake F.', NOW() - INTERVAL '30 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (116, NULL, 13, NULL, 3, 'Tacos were good but smaller than I expected for the price. The barbacoa was flavorful though. Average value overall.', 'Alicia H.', NOW() - INTERVAL '39 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (117, NULL, 13, NULL, 2, 'Mole negro was very watery and lacked the complexity you''d expect from a proper mole. Really disappointing.', 'Malee C.', NOW() - INTERVAL '50 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (118, NULL, 13, NULL, 1, 'Food was cold, tortillas were stiff, and an item was missing. Couldn''t get through to anyone. Wouldn''t order again.', 'Dana L.', NOW() - INTERVAL '63 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (119, NULL, 14, NULL, 5, 'Lamb nihari was extraordinary — the bone marrow richness in the gravy was unlike anything I''ve had. Deeply complex and warming.', 'Priya S.', NOW() - INTERVAL '3 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (120, NULL, 14, NULL, 5, 'Aloo tikki chaat was an explosion of textures and flavors — crunchy, creamy, tangy, and sweet all at once. Phenomenal.', 'Aisha K.', NOW() - INTERVAL '8 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (121, NULL, 14, NULL, 5, 'Murgh malai tikka was incredibly tender and the cream cheese marinade created something very special. Melted in my mouth.', 'Dev R.', NOW() - INTERVAL '14 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (122, NULL, 14, NULL, 4, 'Lamb biryani with fragrant saffron rice was beautifully layered and the meat was perfectly spiced. Really impressive.', 'Sunita P.', NOW() - INTERVAL '21 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (123, NULL, 14, NULL, 4, 'Kerala fish curry was bold and authentic. The coconut milk and raw mango balance was brilliant. Excellent with the kulcha.', 'Tom B.', NOW() - INTERVAL '29 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (124, NULL, 14, NULL, 3, 'Dal makhani was good but not exceptional — I''ve had better. The garlic kulcha was the highlight of the order.', 'Anita P.', NOW() - INTERVAL '38 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (125, NULL, 14, NULL, 2, 'Everything arrived cold and the curry had separated. The flavors underneath were probably good but the experience was poor.', 'Raj K.', NOW() - INTERVAL '49 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (126, NULL, 14, NULL, 1, 'Ordered spicy, got something completely bland. Seekh kebab was dry and flavorless. Very disappointing for the price.', 'Claire F.', NOW() - INTERVAL '62 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (127, NULL, 15, NULL, 5, 'The whole steamed sea bass with sizzling soy oil was an absolute showstopper. The freshness of the fish was impeccable.', 'Linda C.', NOW() - INTERVAL '4 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (128, NULL, 15, NULL, 5, 'Buddha jumps over the wall is extraordinary — an incredibly luxurious broth with sea cucumber and abalone. Worth every penny.', 'Henry K.', NOW() - INTERVAL '9 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (129, NULL, 15, NULL, 5, 'Char siu bao were pillowy and the BBQ pork filling was sweet and perfectly seasoned. Better than most dim sum restaurants.', 'Michelle L.', NOW() - INTERVAL '15 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (130, NULL, 15, NULL, 4, 'Beef ho fun had genuine wok hei — the smoky, charred flavor came through even in delivery. Very impressive technique.', 'Jason W.', NOW() - INTERVAL '22 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (131, NULL, 15, NULL, 4, 'Egg tarts were silky and perfectly baked with a flaky pastry. The quintessential Hong Kong classic done well.', 'Sophie Z.', NOW() - INTERVAL '29 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (132, NULL, 15, NULL, 4, 'Yangzhou fried rice was light and well-seasoned with every grain separate. The char siu pieces were plentiful.', 'Kevin T.', NOW() - INTERVAL '37 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (133, NULL, 15, NULL, 3, 'Dim sum was decent but a few items arrived cool. The siu mai and char siu bao were the best of the lot.', 'Lauren M.', NOW() - INTERVAL '46 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (134, NULL, 15, NULL, 3, 'West Lake beef soup was thin for my taste. Flavors were subtle — perhaps too subtle. Not bad, just very gentle.', 'Yuki H.', NOW() - INTERVAL '56 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (135, NULL, 15, NULL, 2, 'Salt and pepper crab was overcooked and rubbery. For the price, I expected much better quality. Disappointing.', 'Sam W.', NOW() - INTERVAL '67 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (136, NULL, 15, NULL, 1, 'Ordered dim sum, received completely wrong items. Customer service was unhelpful and dismissive. Will not order again.', 'Priya K.', NOW() - INTERVAL '80 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (137, NULL, 16, NULL, 5, 'Salade Lyonnaise was textbook perfect — the poached egg broke over the warm lardons and the frisée. A bistro classic done beautifully.', 'Amélie D.', NOW() - INTERVAL '3 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (138, NULL, 16, NULL, 5, 'Steak frites arrived with the bavette cooked to a perfect medium-rare. The shallot jus was extraordinary. Bravo.', 'Pierre M.', NOW() - INTERVAL '8 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (139, NULL, 16, NULL, 5, 'Profiteroles drenched in Valrhona chocolate sauce were indulgent and perfect. The choux was light as air.', 'Isabelle R.', NOW() - INTERVAL '14 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (140, NULL, 16, NULL, 4, 'Poulet rôti was juicy with crispy golden skin and the tarragon butter was fragrant and wonderful. Excellent.', 'Charlotte B.', NOW() - INTERVAL '21 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (141, NULL, 16, NULL, 3, 'Gratin dauphinois was tasty but arrived very heavy and rich — perhaps too much cream. Decent though.', 'William F.', NOW() - INTERVAL '30 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (142, NULL, 16, NULL, 2, 'Tarte Tatin pastry was completely soggy. The apple filling was good but the texture was completely ruined in transit.', 'Camille R.', NOW() - INTERVAL '42 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (143, NULL, 16, NULL, 1, 'Quenelles arrived looking nothing like expected and tasted reheated. Very expensive for what was delivered. Extremely disappointed.', 'Étienne L.', NOW() - INTERVAL '57 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (144, NULL, 17, NULL, 5, 'Htipiti is the most addictive spread I''ve ever eaten. Whipped feta with roasted peppers and walnuts — I could eat it by the jar.', 'Sophia K.', NOW() - INTERVAL '3 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (145, NULL, 17, NULL, 5, 'Whole grilled octopus was tender, charred, and served with a beautiful fava purée. Restaurant-quality in every way.', 'Elena V.', NOW() - INTERVAL '7 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (146, NULL, 17, NULL, 5, 'Cold mezze spread was stunning — every dip arrived fresh and vibrant. The fattoush and htipiti were exceptional.', 'Yasmin A.', NOW() - INTERVAL '12 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (147, NULL, 17, NULL, 4, 'Moussaka was hearty and beautifully layered. The béchamel was creamy and the lamb was well-seasoned. Very good.', 'Nicholas P.', NOW() - INTERVAL '18 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (148, NULL, 17, NULL, 4, 'Halloumi saganaki was perfectly crispy and the ouzo flame gave it a subtle anise note. Delicious and unusual.', 'George T.', NOW() - INTERVAL '25 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (149, NULL, 17, NULL, 4, 'Lahmacun arrived thin and crispy with vibrant spiced lamb. Rolling it with lemon and herbs was exactly right.', 'Hassan R.', NOW() - INTERVAL '33 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (150, NULL, 17, NULL, 3, 'Keftedes were a bit dry. The fattoush salad was fresh and vibrant though. Mixed experience overall.', 'Anita P.', NOW() - INTERVAL '42 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (151, NULL, 17, NULL, 2, 'Spanakopita were completely soggy — classic phyllo problem with delivery. The filling was tasty but texturally ruined.', 'Raj K.', NOW() - INTERVAL '53 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (152, NULL, 17, NULL, 1, 'Order was half missing and when I tried to report it the restaurant never responded. Charged full price for partial order.', 'Claire F.', NOW() - INTERVAL '67 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (153, NULL, 18, NULL, 5, 'Wagyu short ribs were on another level — the marbling was insane and the marinade enhanced rather than overwhelmed the beef.', 'Jisoo P.', NOW() - INTERVAL '2 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (154, NULL, 18, NULL, 5, 'Hangang Premium Set was worth every penny. The quality of meat and the eight banchan dishes made it a true feast.', 'Min K.', NOW() - INTERVAL '5 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (155, NULL, 18, NULL, 5, 'Mul naengmyeon arrived in a chilled container — cold buckwheat noodles in icy broth were perfect. They know how to pack food.', 'Rachel S.', NOW() - INTERVAL '9 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (156, NULL, 18, NULL, 5, 'Banchan platter alone was worth ordering — all eight dishes were beautifully made, especially the kimchi and japchae.', 'Dana L.', NOW() - INTERVAL '13 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (157, NULL, 18, NULL, 5, 'This is the most authentic Korean BBQ experience I''ve had delivered anywhere. The meat quality is genuinely exceptional.', 'Chris O.', NOW() - INTERVAL '18 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (158, NULL, 18, NULL, 4, 'Spicy pork bulgogi was fiery and well-marinated. The gochujang flavor came through beautifully. Excellent dish.', 'Minji K.', NOW() - INTERVAL '23 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (159, NULL, 18, NULL, 4, 'Sundubu jjigae arrived bubbling in a special container. Silky tofu and clams in that spicy broth — comforting perfection.', 'Daniel Y.', NOW() - INTERVAL '29 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (160, NULL, 18, NULL, 4, 'Pajeon was crispy and loaded with scallion and seafood. The dipping sauce was perfectly balanced. Great starter.', 'Jisoo L.', NOW() - INTERVAL '35 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (161, NULL, 18, NULL, 4, 'Doenjang jjigae was earthy, warming, and deeply savory. Arrived properly hot and the tofu was tender.', 'Kevin T.', NOW() - INTERVAL '42 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (162, NULL, 18, NULL, 3, 'Bingsu was good but had melted a bit in transit. Still tasty — the mango was ripe and the mochi was chewy.', 'Lauren M.', NOW() - INTERVAL '50 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (163, NULL, 18, NULL, 3, 'BBQ is always better grilled yourself so delivery loses something. The banchan and stews are the way to go here.', 'Yuki H.', NOW() - INTERVAL '59 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (164, NULL, 18, NULL, 2, 'Delivery took 90 minutes. Food was lukewarm at best. Not what you want for Korean BBQ. Very frustrating.', 'Sam W.', NOW() - INTERVAL '70 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (165, NULL, 18, NULL, 1, 'Order was wrong and arrived an hour late. Missing key banchan items. Very disappointing for the price point.', 'Priya K.', NOW() - INTERVAL '84 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (166, NULL, 19, NULL, 5, 'Khao soi is simply the best thing I''ve eaten all year. The coconut curry broth, crispy noodles, and braised chicken — absolute perfection.', 'Malee C.', NOW() - INTERVAL '3 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (167, NULL, 19, NULL, 5, 'Phat kraphao with a fried egg is the most authentic Thai street food I''ve had outside Bangkok. Holy basil was fresh and fragrant.', 'Robert N.', NOW() - INTERVAL '8 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (168, NULL, 19, NULL, 5, 'Sai Oua northern sausage was fragrant, herbaceous, and unlike any sausage I''ve had. The lemongrass and galangal were incredible.', 'Alicia H.', NOW() - INTERVAL '14 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (169, NULL, 19, NULL, 4, 'Som tum Isaan was aggressively spicy and funky from the fermented crab — exactly as it should be. Wonderful.', 'Jason W.', NOW() - INTERVAL '21 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (170, NULL, 19, NULL, 4, 'Tod mun pla were crispy and had great bounce. The cucumber relish was the perfect cool contrast. Really good.', 'Emma T.', NOW() - INTERVAL '29 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (171, NULL, 19, NULL, 3, 'Gaeng tai pla is very intense and not for everyone — I found it a bit too fermented for my taste. Authentic though.', 'Sophia K.', NOW() - INTERVAL '38 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (172, NULL, 19, NULL, 2, 'Tom kha gai was thin and lacked the coconut richness I expected. Quite a disappointment for a signature Thai soup.', 'Nicholas P.', NOW() - INTERVAL '50 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (173, NULL, 20, NULL, 5, 'This brisket has the bark and smoke ring of a Texas legend. I cannot believe this came from a delivery box. Absolutely extraordinary.', 'Tyler B.', NOW() - INTERVAL '2 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (174, NULL, 20, NULL, 5, 'Burnt end bites are pure magic — caramelized, smoky, sticky, and falling apart. I''ve eaten at award-winning joints and these stand up.', 'Ashley M.', NOW() - INTERVAL '5 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (175, NULL, 20, NULL, 5, 'St. Louis ribs had the perfect bend test — they flexed without falling apart. Twelve hours of smoke is evident in every bite.', 'Brandon K.', NOW() - INTERVAL '9 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (176, NULL, 20, NULL, 5, 'Banana pudding arrived with the toasted meringue still intact. The custard was made from scratch. A stunning dessert.', 'Megan T.', NOW() - INTERVAL '13 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (177, NULL, 20, NULL, 4, 'Pulled pork sandwich was generously loaded with proper vinegar slaw cutting through the richness. One of the best sandwiches I''ve had.', 'Kayla R.', NOW() - INTERVAL '18 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (178, NULL, 20, NULL, 4, 'Smoked mac and cheese with Gouda was outrageously good. The toasted breadcrumb crust added perfect texture.', 'Josh L.', NOW() - INTERVAL '23 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (179, NULL, 20, NULL, 4, 'Pitmaster''s platter for two was incredible value — brisket, ribs, pulled pork, chicken, four sides. A true BBQ feast.', 'Brianna T.', NOW() - INTERVAL '29 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (180, NULL, 20, NULL, 4, 'Smoked wings with Alabama white sauce were a revelation. The mayo-based sauce sounds odd but it''s brilliant on smoked chicken.', 'Derek L.', NOW() - INTERVAL '36 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (181, NULL, 20, NULL, 4, 'Jalapeño cornbread fresh from a cast iron skillet with honey butter — one of the best sides I''ve ever had delivered.', 'Natalie G.', NOW() - INTERVAL '44 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (182, NULL, 20, NULL, 3, 'Good BBQ — brisket was decent but the flat was a bit dry on my order. The point was perfect though. Sides were excellent.', 'Carlos M.', NOW() - INTERVAL '53 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (183, NULL, 20, NULL, 3, 'Ribs were good but not quite fall-off-the-bone. The rub was excellent though. Solid BBQ overall.', 'Jessica R.', NOW() - INTERVAL '63 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (184, NULL, 20, NULL, 2, 'Brisket arrived cold and had dried out significantly. BBQ really needs to be eaten fresh off the smoker. Poor delivery experience.', 'Marco V.', NOW() - INTERVAL '75 days');
INSERT INTO reviews (id, user_id, restaurant_id, order_id, rating, comment, reviewer_name, created_at) OVERRIDING SYSTEM VALUE VALUES (185, NULL, 20, NULL, 1, 'Ordered a full rack of ribs and received half a rack. When I contacted them I got no response. Complete rip-off.', 'Omar A.', NOW() - INTERVAL '90 days');
